mapper.select:
/* GoodsMapper.getAdminGoodsList: 관리자 상품 목록 조회 */ SELECT GB.GOODS_ID , GB.BRAND_NO , BB.BRAND_NM AS BRAND_NM , GB.ERP_STYLE_CD , GB.GOODS_NM , GB.GOODS_STAT_CD , FN_GET_CODE_NM('GOODS_STAT', GB.GOODS_STAT_CD) AS GOODS_STAT_NM , GB.GOODS_DIV_CD , FN_GET_CODE_NM('GOODS_DIV', GB.GOODS_DIV_CD) AS GOODS_DIV_NM , GB.SHOW_YN , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = GB.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH , GB.REG_DT , GB.UDT_DT FROM GOODS_BASE GB LEFT JOIN BRAND_BASE BB ON BB.BRAND_NO = GB.BRAND_NO WHERE 1 = 1
AND GB.GOODS_STAT_CD = #{goodsStatCd}
AND GB.GOODS_DIV_CD = #{goodsDivCd}
AND GB.GOODS_MERCH_ID = #{goodsMerchId}
AND GB.SHOW_YN = #{showYn}
AND GB.BRAND_NO = #{brandNo}
AND EXISTS ( SELECT 1 FROM CATEGORY_GOODS CG WHERE CG.GOODS_ID = GB.GOODS_ID AND CG.CATEGORY_ID = #{categoryId} )
AND GB.GOODS_ID LIKE CONCAT(#{searchValue}, '%')
AND GB.ERP_STYLE_CD LIKE CONCAT(#{searchValue}, '%')
AND MATCH(GB.GOODS_NM) AGAINST(#{searchKeyword} IN BOOLEAN MODE)
ORDER BY GB.REG_DT DESC LIMIT #{pageSize} OFFSET #{offset}

/* GoodsMapper.getAdminGoodsCount: 관리자 상품 목록 조회 수 */
SELECT COUNT(1)
  FROM GOODS_BASE GB
 WHERE 1 = 1

   AND GB.GOODS_STAT_CD = #{goodsStatCd}


   AND GB.GOODS_DIV_CD = #{goodsDivCd}


   AND GB.GOODS_MERCH_ID = #{goodsMerchId}


   AND GB.SHOW_YN = #{showYn}


   AND GB.BRAND_NO = #{brandNo}


   AND EXISTS (
       SELECT 1
         FROM CATEGORY_GOODS CG
        WHERE CG.GOODS_ID = GB.GOODS_ID
          AND CG.CATEGORY_ID = #{categoryId}
   )




   AND GB.GOODS_ID LIKE CONCAT(#{searchValue}, '%')


   AND GB.ERP_STYLE_CD LIKE CONCAT(#{searchValue}, '%')


   AND MATCH(GB.GOODS_NM) AGAINST(#{searchKeyword} IN BOOLEAN MODE)

mapper.insert:
/* GoodsMapper.insertAdminGoods: 관리자 상품 등록 */
INSERT INTO GOODS_BASE (
       GOODS_ID
     , BRAND_NO
     , GOODS_DIV_CD
     , GOODS_STAT_CD
     , GOODS_NM
     , GOODS_GROUP_ID
     , GOODS_MERCH_ID
     , SUPPLY_AMT
     , SALE_AMT
     , SHOW_YN
     , ERP_SUPPLY_AMT
     , ERP_COST_AMT
     , ERP_STYLE_CD
     , ERP_COLOR_CD
     , ERP_MERCH_CD
     , REG_NO
     , UDT_NO
) VALUES (
       #{goodsId}
     , #{brandNo}
     , #{goodsDivCd}
     , #{goodsStatCd}
     , #{goodsNm}
     , #{goodsGroupId}
     , #{goodsMerchId}
     , #{supplyAmt}
     , #{saleAmt}
     , #{showYn}
     , #{erpSupplyAmt}
     , #{erpCostAmt}
     , #{erpStyleCd}
     , #{erpColorCd}
     , #{erpMerchCd}
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* GoodsMapper.updateAdminGoods: 관리자 상품 수정 */
UPDATE GOODS_BASE
   SET GOODS_DIV_CD = #{goodsDivCd}
     , GOODS_STAT_CD = #{goodsStatCd}
     , GOODS_NM = #{goodsNm}
     , GOODS_GROUP_ID = #{goodsGroupId}
     , GOODS_MERCH_ID = #{goodsMerchId}
     , SUPPLY_AMT = #{supplyAmt}
     , SALE_AMT = #{saleAmt}
     , SHOW_YN = #{showYn}
     , ERP_SUPPLY_AMT = #{erpSupplyAmt}
     , ERP_COST_AMT = #{erpCostAmt}
     , ERP_STYLE_CD = #{erpStyleCd}
     , ERP_COLOR_CD = #{erpColorCd}
     , ERP_MERCH_CD = #{erpMerchCd}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE GOODS_ID = #{goodsId}

mapper.select:
/* GoodsMapper.getCategoryList: 카테고리 목록 조회 */ SELECT CATEGORY_ID , PARENT_CATEGORY_ID , CATEGORY_LEVEL , CATEGORY_NM , DISP_ORD , SHOW_YN FROM CATEGORY WHERE SHOW_YN = 'Y'
AND CATEGORY_LEVEL = #{categoryLevel}
AND PARENT_CATEGORY_ID = #{parentCategoryId}
ORDER BY DISP_ORD ASC, CATEGORY_ID ASC

/* GoodsMapper.getAdminCategoryMaxDispOrd: 관리자 카테고리 정렬 순서 최대값 조회 */
SELECT COALESCE(MAX(DISP_ORD), 0)
  FROM CATEGORY
 WHERE PARENT_CATEGORY_ID = #{parentCategoryId}

/* GoodsMapper.getAdminCategoryMaxId: 관리자 카테고리 최대 코드 조회 */
SELECT MAX(CATEGORY_ID)
  FROM CATEGORY
 WHERE PARENT_CATEGORY_ID = #{parentCategoryId}

